async (params, browser) => {
  // Open page
  await browser.open(`https://huggingface.co/papers/${params.paper_id}`)

  // Wait for content
  await browser.waitForSelector('h1, main', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim()||''; const authorEls = document.querySelectorAll('main a[href]'); const authors = []; authorEls.forEach(a => { const href = a.getAttribute('href')||''; if (href.match(/^\/[a-zA-Z0-9_-]+$/) && !href.includes('/papers') && !href.includes('/models') && !href.includes('/datasets') && !href.includes('/spaces')) { const name = a.textContent.trim(); if (name && name.length < 60 && !name.includes('\n')) authors.push(name); } }); const allPs = Array.from(document.querySelectorAll('main p')); const abstract = allPs.filter(p => p.textContent.trim().length > 100).map(p => p.textContent.trim()).join(' ').substring(0, 2000) || ''; const dateEl = Array.from(document.querySelectorAll('main *')).find(el => el.textContent.match(/Published on|Submitted/)); const date = dateEl?.textContent?.trim()||''; const arxiv = document.querySelector('a[href*="arxiv.org"]')?.href||''; const linkedModels = Array.from(document.querySelectorAll('a[href*="/models"], a[href]:not([href*="papers"])')).filter(a => { const h = a.getAttribute('href')||''; return h.match(/^\/[^/]+\/[^/]+$/) && !h.includes('/papers/'); }).slice(0,10).map(a => a.textContent.trim()); return { title, authors: [...new Set(authors)].slice(0,20), abstract, date, arxiv_link: arxiv, linked_models: linkedModels, url: window.location.href }`)

  return page_data
}
